import React, { useEffect, useState } from "react";
import Papa from "papaparse";

function App() {
    const [data, setData] = useState([]);

    useEffect(() => {
        fetch("/tedarik_performans.csv")
            .then((res) => res.text())
            .then((csvText) => {
                const results = Papa.parse(csvText, {
                    delimiter: ";", // Noktalı virgül ile ayrılmış CSV için
                    header: true,   // İlk satırı başlık olarak kullan
                    skipEmptyLines: true,
                });
                setData(results.data);
            })
            .catch((error) => console.error("CSV okuma hatası:", error));
    }, []);

    return (
        <div className="App">
            <h1>TEDARİK PERFORMANS RAPORU</h1>
            <table border="1" style={{ borderCollapse: "collapse", width: "100%" }}>
                <thead>
                    <tr>
                        {data.length > 0 &&
                            Object.keys(data[0]).map((key) => (
                                <th key={key}>{key}</th>
                            ))}
                    </tr>
                </thead>
                <tbody>
                    {data.map((row, idx) => (
                        <tr key={idx}>
                            {Object.values(row).map((val, i) => (
                                <td key={i}>{val}</td>
                            ))}
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
}

export default App;
